class Solution:
    def numMovesStones(self, a, b, c):
        # Brute force minimum via BFS over reachable stone configurations
        # (positions are small so the search space is tiny), maximum by gaps.
        start = tuple(sorted((a, b, c)))
        from collections import deque
        seen = {start: 0}
        q = deque([start])
        min_moves = None
        while q:
            state = q.popleft()
            x, y, z = state
            if z - x == 2:
                min_moves = seen[state]
                break
            # move endpoint x to some k in (x, z), k != y
            for k in range(x + 1, z):
                if k == y:
                    continue
                ns = tuple(sorted((k, y, z)))
                if ns not in seen:
                    seen[ns] = seen[state] + 1
                    q.append(ns)
            for k in range(x + 1, z):
                if k == y:
                    continue
                ns = tuple(sorted((x, y, k)))
                if ns not in seen:
                    seen[ns] = seen[state] + 1
                    q.append(ns)
        if min_moves is None:
            min_moves = 0
        x, y, z = start
        max_moves = (y - x - 1) + (z - y - 1)
        return [min_moves, max_moves]

