class Solution:
    def numMovesStones(self, a, b, c):
        x, y, z = sorted((a, b, c))
        if z - x == 2:
            mn = 0
        elif (y - x) <= 2 or (z - y) <= 2:
            mn = 1
        else:
            mn = 2
        mx = (z - x) - 2
        return [mn, mx]

