var numMovesStones = function(a, b, c) {
    const arr = [a, b, c].sort((p, q) => p - q);
    const [x, y, z] = arr;
    let mn;
    if (z - x === 2) mn = 0;
    else if ((y - x) <= 2 || (z - y) <= 2) mn = 1;
    else mn = 2;
    const mx = (z - x) - 2;
    return [mn, mx];
};
